using System.Text.Json;using NewSmartAIFactory.CompanyApi.Models;using Npgsql;using NpgsqlTypes;
namespace NewSmartAIFactory.CompanyApi.Services;
public sealed class EventStoreService
{
 private readonly string _connectionString;public EventStoreService(IConfiguration c)=>_connectionString=c.GetConnectionString("Postgres")??throw new InvalidOperationException("Connection string 'Postgres' is missing.");
 public async Task<DomainEventEnvelope> AppendAsync(CreateDomainEventRequest r,CancellationToken token){var id=Guid.NewGuid();var occurred=DateTimeOffset.UtcNow;var correlation=string.IsNullOrWhiteSpace(r.CorrelationId)?id.ToString("N"):r.CorrelationId;var actor=string.IsNullOrWhiteSpace(r.Actor)?"system":r.Actor;var json=r.Payload?.GetRawText()??"{}";const string sql="insert into domain_events(id,event_type,aggregate_type,aggregate_id,project_id,correlation_id,actor,payload,occurred_at_utc) values(@id,@type,@aggregateType,@aggregateId,@project,@correlation,@actor,@payload,@occurred)";await using var c=new NpgsqlConnection(_connectionString);await c.OpenAsync(token);await using var cmd=new NpgsqlCommand(sql,c);cmd.Parameters.AddWithValue("id",id);cmd.Parameters.AddWithValue("type",r.EventType);cmd.Parameters.AddWithValue("aggregateType",r.AggregateType);cmd.Parameters.AddWithValue("aggregateId",r.AggregateId);cmd.Parameters.AddWithValue("project",(object?)r.ProjectId??DBNull.Value);cmd.Parameters.AddWithValue("correlation",correlation);cmd.Parameters.AddWithValue("actor",actor);cmd.Parameters.AddWithValue("payload",NpgsqlDbType.Jsonb,json);cmd.Parameters.AddWithValue("occurred",occurred);await cmd.ExecuteNonQueryAsync(token);using var doc=JsonDocument.Parse(json);return new DomainEventEnvelope(id,r.EventType,r.AggregateType,r.AggregateId,r.ProjectId,correlation,actor,doc.RootElement.Clone(),occurred);}
 public async Task<IReadOnlyList<DomainEventEnvelope>> ListAsync(string? projectId,string? eventType,int limit,CancellationToken token){const string sql="select id,event_type,aggregate_type,aggregate_id,project_id,correlation_id,actor,payload::text,occurred_at_utc from domain_events where (@project is null or project_id=@project) and (@type is null or event_type=@type) order by occurred_at_utc desc limit @limit";var items=new List<DomainEventEnvelope>();await using var c=new NpgsqlConnection(_connectionString);await c.OpenAsync(token);await using var cmd=new NpgsqlCommand(sql,c);cmd.Parameters.Add("project",NpgsqlDbType.Text).Value=(object?)projectId??DBNull.Value;cmd.Parameters.Add("type",NpgsqlDbType.Text).Value=(object?)eventType??DBNull.Value;cmd.Parameters.AddWithValue("limit",Math.Clamp(limit,1,200));await using var r=await cmd.ExecuteReaderAsync(token);while(await r.ReadAsync(token)){using var doc=JsonDocument.Parse(r.GetString(7));items.Add(new DomainEventEnvelope(r.GetGuid(0),r.GetString(1),r.GetString(2),r.GetString(3),r.IsDBNull(4)?null:r.GetString(4),r.GetString(5),r.GetString(6),doc.RootElement.Clone(),r.GetFieldValue<DateTimeOffset>(8)));}return items;}
}
